let raw: any = fetchSomething();

// No error — TypeScript trusts you completely
raw.length;
raw.toUpperCase();
raw.nonExistent();
raw();

// Propagates: assigning any to a typed variable silences future checks
const n: number = raw; // allowed — but raw may not be a number at runtime
n.toFixed(2);          // TypeScript is happy; runtime crash if raw was a string

// any from JSON.parse
const parsed: any = JSON.parse('{"id":1}');
parsed.id;           // allowed; no IntelliSense for id

// Implicit any — parameter has no annotation, TypeScript can't infer
function greet(name) {  // TS7006: Parameter 'name' implicitly has an 'any' type
  return 'Hello ' + name;
}

// Fix — annotate the parameter
function greet(name: string): string {
  return 'Hello ' + name;
}

// Implicit any from empty array
const items = [];         // never[] in strict mode
// Fix
const items: string[] = [];

// Type assertion to escape any (use sparingly)
const data = someLib() as { id: number; name: string };
console.log(data.id); // number — TypeScript believes the assertion

let input: unknown = getSomeInput();

// These are all compile errors — TypeScript refuses to operate on unknown directly
// input.toUpperCase(); // TS2571
// const n: number = input; // TS2322
// input();             // TS2571

// You must narrow first
if (typeof input === 'string') {
  console.log(input.toUpperCase()); // OK — narrowed to string
}

if (typeof input === 'number') {
  console.log(input.toFixed(2));    // OK — narrowed to number
}

if (input instanceof Date) {
  console.log(input.toISOString()); // OK — narrowed to Date
}

// Narrowing with type guards
function isUser(v: unknown): v is { id: number; name: string } {
  return (
    typeof v === 'object' && v !== null &&
    'id' in v && 'name' in v
  );
}

if (isUser(input)) {
  console.log(input.id, input.name); // fully typed
}

// HTTP response body — you own the type, not the network
async function fetchUser(id: number): Promise<unknown> {
  const res = await fetch(`/api/users/${id}`);
  return res.json();  // response body is unknown
}

// Safe consumer
async function printUser(id: number): Promise<void> {
  const data = await fetchUser(id);
  if (isUser(data)) {
    console.log(data.name); // typed
  } else {
    console.error('Unexpected response shape', data);
  }
}

// catch clause — error is unknown in TypeScript 4.4+
try {
  JSON.parse('bad json');
} catch (e: unknown) {
  if (e instanceof Error) {
    console.error(e.message); // string
  } else {
    console.error('Non-Error thrown', e);
  }
}

// Unconditional throw — never returns normally
function fail(message: string): never {
  throw new Error(message);
}

// Infinite loop — never returns
function runForever(): never {
  while (true) {
    // event loop
  }
}

// Use never as a fallback in conditional logic
function assertNever(x: never): never {
  throw new Error('Unhandled value: ' + JSON.stringify(x));
}

type Status = 'pending' | 'active' | 'archived';

function describe(s: Status): string {
  switch (s) {
    case 'pending':  return 'Waiting for review';
    case 'active':   return 'Currently active';
    case 'archived': return 'No longer in use';
    default:
      // If you add a new Status value and forget to handle it here,
      // TypeScript errors: "'new-value' is not assignable to parameter of type 'never'"
      return assertNever(s);
  }
}

// Adding a new status value
type StatusV2 = Status | 'suspended';

function describeV2(s: StatusV2): string {
  switch (s) {
    case 'pending':   return 'Waiting';
    case 'active':    return 'Active';
    case 'archived':  return 'Archived';
    // Forgot 'suspended'
    default:
      return assertNever(s); // TS2345 — 'suspended' is not assignable to 'never'
  }
}

type A = string | number | boolean;

// After narrowing out all possibilities, the remainder is never
function processA(a: A): string {
  if (typeof a === 'string') return a.toUpperCase();
  if (typeof a === 'number') return a.toFixed();
  if (typeof a === 'boolean') return String(a);
  // a: never here — TypeScript knows this code can't be reached
  const _exhausted: never = a;
  return _exhausted; // never is assignable to any return type
}

// Conditional type produces never when impossible
type NonNullable<T> = T extends null | undefined ? never : T;
type A2 = NonNullable<string | null>; // string

// Filtering a union with never
type OnlyStrings<T> = T extends string ? T : never;
type S = OnlyStrings<string | number | boolean>; // string

import { HttpClient } from '@angular/common/http';
import { map } from 'rxjs/operators';

interface Product { id: number; name: string; price: number }

function isProduct(v: unknown): v is Product {
  return (
    typeof v === 'object' && v !== null &&
    'id' in v && 'name' in v && 'price' in v &&
    typeof (v as Product).price === 'number'
  );
}

@Injectable({ providedIn: 'root' })
class ProductService {
  constructor(private http: HttpClient) {}

  getProduct(id: number) {
    // HttpClient returns Observable<unknown> when typed generically
    return this.http.get<unknown>(`/api/products/${id}`).pipe(
      map(data => {
        if (!isProduct(data)) throw new Error('Invalid product shape');
        return data; // Product — fully typed after guard
      })
    );
  }
}

type Route = '/' | '/about' | '/contact';

function getTitle(route: Route): string {
  switch (route) {
    case '/':        return 'Home';
    case '/about':   return 'About Us';
    case '/contact': return 'Contact';
    default:         return assertNever(route);
  }
}

// Angular guard — return never for impossible branches
import { ActivatedRouteSnapshot } from '@angular/router';

function extractSegment(snapshot: ActivatedRouteSnapshot, key: string): string {
  const val = snapshot.paramMap.get(key);
  if (val === null) {
    return fail(`Route parameter "${key}" is required`); // never
  }
  return val; // string — TypeScript knows null was handled
}

// NonNullable removes null and undefined from a union
type NonNullable<T> = T extends null | undefined ? never : T;
type S = NonNullable<string | null | undefined>; // string

// Exclude a member from a union
type Exclude<T, U> = T extends U ? never : T;
type Nums = Exclude<string | number | boolean, string>; // number | boolean

// Extract matching members from a union
type Extract<T, U> = T extends U ? T : never;
type Strings = Extract<string | number | boolean, string>; // string

// ReturnType — extracts the return type of a function
type ReturnType<T extends (...args: never) => unknown> =
  T extends (...args: never) => infer R ? R : never;

function greet(name: string): string { return 'Hello ' + name; }
type GreetReturn = ReturnType<typeof greet>; // string

// Parameters — extracts parameter types as a tuple
type Parameters<T extends (...args: never) => unknown> =
  T extends (...args: infer P) => unknown ? P : never;
type GreetParams = Parameters<typeof greet>; // [name: string]

type Color = 'red' | 'green' | 'blue';

function paintWith(color: Color): string {
  switch (color) {
    case 'red':   return '#ff0000';
    case 'green': return '#00ff00';
    case 'blue':  return '#0000ff';
    default: {
      // Compile-time proof that all cases are handled
      const _exhaustive: never = color;
      return _exhaustive;
    }
  }
}

// If you add 'purple' to Color but forget to add the case,
// TypeScript reports:
// Type 'purple' is not assignable to type 'never'
// pointing exactly to the missing branch.

// --- 1. typeof narrowing ---
function format(value: unknown): string {
  if (typeof value === 'string') return value.trim();
  if (typeof value === 'number') return value.toFixed(2);
  if (typeof value === 'boolean') return String(value);
  return JSON.stringify(value);
}

// --- 2. instanceof narrowing ---
function handleError(e: unknown): string {
  if (e instanceof TypeError) return 'Type error: ' + e.message;
  if (e instanceof RangeError) return 'Range error: ' + e.message;
  if (e instanceof Error) return 'Error: ' + e.message;
  return String(e);
}

// --- 3. User-defined type predicates ---
interface ApiResponse<T> {
  data: T;
  status: number;
}

function isApiResponse<T>(v: unknown, guard: (x: unknown) => x is T): v is ApiResponse<T> {
  return (
    typeof v === 'object' && v !== null &&
    'data' in v && 'status' in v &&
    typeof (v as ApiResponse<T>).status === 'number' &&
    guard((v as ApiResponse<T>).data)
  );
}

function isNumber(x: unknown): x is number {
  return typeof x === 'number';
}

const raw: unknown = { data: 42, status: 200 };
if (isApiResponse(raw, isNumber)) {
  console.log(raw.data.toFixed(2)); // raw.data: number
}

// Conceptual pattern — same approach works with Zod, Valibot, io-ts
// (This example shows the structural idea without library imports)

// Manual guard (verbose for nested shapes)
interface Config {
  host: string;
  port: number;
  ssl?: boolean;
}

function isConfig(v: unknown): v is Config {
  if (typeof v !== 'object' || v === null) return false;
  const c = v as Record<string, unknown>;
  if (typeof c.host !== 'string') return false;
  if (typeof c.port !== 'number') return false;
  if ('ssl' in c && typeof c.ssl !== 'boolean') return false;
  return true;
}

function loadConfig(raw: unknown): Config {
  if (!isConfig(raw)) throw new TypeError('Invalid config');
  return raw; // Config
}

